import{_ as d}from"./chunks/ue-quick-menu.CKRco9JD.js";import{_ as a,o as r,c as o,ag as e}from"./chunks/framework.BqfgOMAh.js";const p=JSON.parse('{"title":"UE 快速菜单","description":"","frontmatter":{},"headers":[],"relativePath":"zh/guide/quick-menu.md","filePath":"zh/guide/quick-menu.md"}'),n={name:"zh/guide/quick-menu.md"};function h(s,t,l,i,b,g){return r(),o("div",null,[...t[0]||(t[0]=[e('<h1 id="ue-快速菜单" tabindex="-1">UE 快速菜单 <a class="header-anchor" href="#ue-快速菜单" aria-label="Permalink to &quot;UE 快速菜单&quot;">​</a></h1><p>快速菜单让你无需切换到 NexusFlow 侧边栏，即可在 Unreal Engine 编辑器内直接调用 AI 操作。</p><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>NexusFlow 在 UE 编辑器中提供了 <strong>4 个入口</strong>，共 <strong>17 项 AI 操作</strong>：</p><table tabindex="0"><thead><tr><th>入口</th><th>位置</th><th>操作数量</th></tr></thead><tbody><tr><td><a href="#蓝图编辑器右键菜单">蓝图编辑器右键菜单</a></td><td>在蓝图图表中右键</td><td>13 项</td></tr><tr><td><a href="#内容浏览器右键菜单">内容浏览器右键菜单</a></td><td>在蓝图资产上右键</td><td>2 项</td></tr><tr><td><a href="#蓝图编辑器工具栏">蓝图编辑器工具栏</a></td><td>蓝图编辑器顶部工具栏</td><td>2 项</td></tr><tr><td><a href="#关卡编辑器工具栏">关卡编辑器工具栏</a></td><td>主编辑器工具栏（NexusFlow 按钮）</td><td>连接状态 + 快捷入口</td></tr></tbody></table><p>选择操作后，NexusFlow 会自动：</p><ol><li>打开侧边栏（如果隐藏）并聚焦聊天输入框</li><li>发送预设 Prompt 和完整的蓝图上下文</li><li>在侧边栏中显示 AI 回复</li></ol><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>如果 AI 正在处理请求，快速菜单会弹出 toast 通知并丢弃新 Prompt，避免冲突。</p></div><h2 id="蓝图编辑器右键菜单" tabindex="-1">蓝图编辑器右键菜单 <a class="header-anchor" href="#蓝图编辑器右键菜单" aria-label="Permalink to &quot;蓝图编辑器右键菜单&quot;">​</a></h2><p><img src="'+d+'" alt="蓝图编辑器右键菜单中的 NexusFlow AI 子菜单"></p><p>打开蓝图后，可选中一个或多个节点，然后在图表区域 <strong>右键</strong>。NexusFlow 子菜单会根据你的选择状态动态显示对应操作。</p><h3 id="选择模式" tabindex="-1">选择模式 <a class="header-anchor" href="#选择模式" aria-label="Permalink to &quot;选择模式&quot;">​</a></h3><p>每个操作都有一个 <strong>选择模式</strong>，控制它何时出现在菜单中：</p><table tabindex="0"><thead><tr><th>模式</th><th>含义</th><th>示例</th></tr></thead><tbody><tr><td><code>any</code></td><td>始终显示，不管是否选中节点</td><td>解释图表、整理布局</td></tr><tr><td><code>single</code></td><td>仅在 <strong>恰好选中 1 个节点</strong> 时显示</td><td>解释选中节点</td></tr><tr><td><code>multi</code></td><td>仅在 <strong>选中 2 个及以上节点</strong> 时显示</td><td>提取为函数</td></tr></tbody></table><h3 id="可用操作-13-项" tabindex="-1">可用操作（13 项） <a class="header-anchor" href="#可用操作-13-项" aria-label="Permalink to &quot;可用操作（13 项）&quot;">​</a></h3><h4 id="解释与分析" tabindex="-1">解释与分析 <a class="header-anchor" href="#解释与分析" aria-label="Permalink to &quot;解释与分析&quot;">​</a></h4><table tabindex="0"><thead><tr><th>操作</th><th>选择模式</th><th>说明</th></tr></thead><tbody><tr><td><strong>解释图表</strong></td><td>any</td><td>分析整个图表的逻辑和数据流</td></tr><tr><td><strong>解释选中节点</strong></td><td>single</td><td>深入分析选中节点的功能</td></tr></tbody></table><h4 id="优化与重构" tabindex="-1">优化与重构 <a class="header-anchor" href="#优化与重构" aria-label="Permalink to &quot;优化与重构&quot;">​</a></h4><table tabindex="0"><thead><tr><th>操作</th><th>选择模式</th><th>说明</th></tr></thead><tbody><tr><td><strong>优化选中节点</strong></td><td>single</td><td>建议性能或可读性改进</td></tr><tr><td><strong>提取为函数</strong></td><td>multi</td><td>将选中节点提取为可复用函数</td></tr><tr><td><strong>提取为宏</strong></td><td>multi</td><td>将选中节点提取为宏</td></tr><tr><td><strong>整理布局</strong></td><td>any</td><td>重新排列节点位置以提升可读性</td></tr><tr><td><strong>简化连线</strong></td><td>any</td><td>减少不必要的连线和重定向节点</td></tr></tbody></table><h4 id="文档补全" tabindex="-1">文档补全 <a class="header-anchor" href="#文档补全" aria-label="Permalink to &quot;文档补全&quot;">​</a></h4><table tabindex="0"><thead><tr><th>操作</th><th>选择模式</th><th>说明</th></tr></thead><tbody><tr><td><strong>图表文档</strong></td><td>any</td><td>为整个图表生成文档</td></tr><tr><td><strong>函数文档</strong></td><td>any</td><td>生成参数和返回值说明文档</td></tr></tbody></table><h4 id="清理与修复" tabindex="-1">清理与修复 <a class="header-anchor" href="#清理与修复" aria-label="Permalink to &quot;清理与修复&quot;">​</a></h4><table tabindex="0"><thead><tr><th>操作</th><th>选择模式</th><th>说明</th></tr></thead><tbody><tr><td><strong>清理未使用变量</strong></td><td>any</td><td>识别并移除未使用的变量</td></tr><tr><td><strong>修复编译错误</strong></td><td>any</td><td>分析并建议修复编译错误</td></tr><tr><td><strong>修复断裂引用</strong></td><td>any</td><td>查找并解决断裂的资产/节点引用</td></tr><tr><td><strong>修复过时节点</strong></td><td>any</td><td>识别已弃用的节点并建议替代方案</td></tr></tbody></table><h2 id="内容浏览器右键菜单" tabindex="-1">内容浏览器右键菜单 <a class="header-anchor" href="#内容浏览器右键菜单" aria-label="Permalink to &quot;内容浏览器右键菜单&quot;">​</a></h2><p>在 <strong>内容浏览器</strong> 中，右键点击一个或多个蓝图资产，即可访问资产级别的 NexusFlow 操作。</p><table tabindex="0"><thead><tr><th>操作</th><th>选择模式</th><th>说明</th></tr></thead><tbody><tr><td><strong>解释蓝图</strong></td><td>any</td><td>分析蓝图的整体结构和用途</td></tr><tr><td><strong>蓝图文档</strong></td><td>any</td><td>为蓝图生成完整文档</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">INFO</p><p>这些操作针对整个蓝图资产，而非单个节点。非常适合快速了解他人编写的蓝图。</p></div><h2 id="蓝图编辑器工具栏" tabindex="-1">蓝图编辑器工具栏 <a class="header-anchor" href="#蓝图编辑器工具栏" aria-label="Permalink to &quot;蓝图编辑器工具栏&quot;">​</a></h2><p>打开蓝图后，<strong>蓝图编辑器工具栏</strong>（顶部）会出现两个按钮：</p><table tabindex="0"><thead><tr><th>操作</th><th>说明</th></tr></thead><tbody><tr><td><strong>审查蓝图</strong></td><td>对当前蓝图进行质量审查（结构、命名、最佳实践）</td></tr><tr><td><strong>总结蓝图</strong></td><td>生成蓝图功能的简明摘要</td></tr></tbody></table><p>工具栏按钮始终可见，不依赖节点选择状态。</p><h2 id="关卡编辑器工具栏" tabindex="-1">关卡编辑器工具栏 <a class="header-anchor" href="#关卡编辑器工具栏" aria-label="Permalink to &quot;关卡编辑器工具栏&quot;">​</a></h2><p>NexusFlow 按钮位于 <strong>关卡编辑器主工具栏</strong>，提供快捷入口和连接状态一览。</p><h3 id="连接状态" tabindex="-1">连接状态 <a class="header-anchor" href="#连接状态" aria-label="Permalink to &quot;连接状态&quot;">​</a></h3><p>按钮图标会根据 NexusFlow 桌面应用是否运行而变化：</p><table tabindex="0"><thead><tr><th>状态</th><th>图标</th><th>点击行为</th></tr></thead><tbody><tr><td><strong>已连接</strong></td><td>彩色图标</td><td>打开侧边栏并聚焦聊天输入框</td></tr><tr><td><strong>未连接</strong></td><td>灰色图标</td><td>显示下载链接通知</td></tr></tbody></table><h3 id="未连接通知" tabindex="-1">未连接通知 <a class="header-anchor" href="#未连接通知" aria-label="Permalink to &quot;未连接通知&quot;">​</a></h3><p>当 NexusFlow 未运行时，点击工具栏按钮会显示通知弹窗：</p><ul><li>提示需要安装 NexusFlow 桌面应用</li><li><strong>GitHub</strong> 下载链接 — 最新版本发布页</li><li><strong>Mirror</strong> 下载链接 — 国内加速下载</li></ul><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>关卡编辑器工具栏按钮是快捷入口，不是 AI 操作触发器。要使用 AI 操作，请通过蓝图编辑器右键菜单、内容浏览器右键菜单或蓝图编辑器工具栏。</p></div><h2 id="语言支持" tabindex="-1">语言支持 <a class="header-anchor" href="#语言支持" aria-label="Permalink to &quot;语言支持&quot;">​</a></h2><p>快速菜单项名称会根据 <strong>UE 编辑器的语言设置</strong> 显示：</p><table tabindex="0"><thead><tr><th>语言</th><th>示例</th></tr></thead><tbody><tr><td>English</td><td>Explain Graph</td></tr><tr><td>简体中文</td><td>解释图表</td></tr><tr><td>繁體中文</td><td>解釋圖表</td></tr></tbody></table><p>语言由 UE 的区域设置决定，而非 NexusFlow 应用的语言设置。</p><h2 id="上下文信息" tabindex="-1">上下文信息 <a class="header-anchor" href="#上下文信息" aria-label="Permalink to &quot;上下文信息&quot;">​</a></h2><p>触发快速菜单操作时，以下上下文信息会被自动收集并发送给 AI：</p><ul><li><strong>蓝图资产路径</strong> — 当前蓝图在项目中的位置</li><li><strong>图名称</strong> — 当前正在编辑的图（如 EventGraph、某个函数图）</li><li><strong>选中节点 ID</strong> — 所有被选中的蓝图节点（如有）</li><li><strong>触发入口</strong> — 操作来自哪个菜单</li></ul><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>快速菜单需要 NexusFlow 桌面应用已启动并与 UE 建立连接。如果连接断开，菜单项仍会显示，但操作无法发送。</p></div>',48)])])}const m=a(n,[["render",h]]);export{p as __pageData,m as default};
